public function getReference(string $entityName, mixed $id): object|null
    {
        $class = $this->metadataFactory->getMetadataFor(ltrim($entityName, '\\'));

        if (! is_array($id)) {
            $id = [$class->identifier[0] => $id];
        }

        $sortedId = [];

        foreach ($class->identifier as $identifier) {
            if (! isset($id[$identifier])) {
                throw MissingIdentifierField::fromFieldAndClass($identifier, $class->name);
            }

            $sortedId[$identifier] = $id[$identifier];
            unset($id[$identifier]);
        }

        if ($id) {
            throw UnrecognizedIdentifierFields::fromClassAndFieldNames($class->name, array_keys($id));
        }

        $entity = $this->unitOfWork->tryGetById($sortedId, $class->rootEntityName);

        // Check identity map first, if its already in there just return it.
        if ($entity !== false) {
            return $entity instanceof $class->name ? $entity : null;
        }

        if ($class->subClasses) {
            return $this->find($entityName, $sortedId);
        }

        $entity = $this->proxyFactory->getProxy($class->name, $sortedId);

        $this->unitOfWork->registerManaged($entity, $sortedId, []);

        return $entity;
    }

private function extractDiff(array $trace, int $x, int $y, array $old, array $new): array {
    $result = [];
    for ($d = \count($trace) - 1; $d >= 0; $d--) {
        $v = $trace[$d];
        $k = $x - $y;

        if ($k === -$d || ($k !== $d && $v[$k - 1] < $v[$k + 1])) {
            $prevK = $k + 1;
        } else {
            $prevK = $k - 1;
        }

        $prevX = $v[$prevK];
        $prevY = $prevX - $prevK;

        while ($x > $prevX && $y > $prevY) {
            $result[] = new DiffElem(DiffElem::TYPE_KEEP, $old[$x - 1], $new[$y - 1]);
            $x--;
            $y--;
        }

        if ($d === 0) {
            break;
        }

        while ($x > $prevX) {
            $result[] = new DiffElem(DiffElem::TYPE_REMOVE, $old[$x - 1], null);
            $x--;
        }

        while ($y > $prevY) {
            $result[] = new DiffElem(DiffElem::TYPE_ADD, null, $new[$y - 1]);
            $y--;
        }
    }
    return array_reverse($result);
}

public function toRegionName(?DateTimeInterface $date = null, int $isDST = 1): ?string
    {
        $name = $this->getName();
        $firstChar = substr($name, 0, 1);

        if ($firstChar !== '+' && $firstChar !== '-') {
            return $name;
        }

        $date = $this->resolveCarbon($date);

        // Integer construction no longer supported since PHP 8
        // @codeCoverageIgnoreStart
        try {
            $offset = @$this->getOffset($date) ?: 0;
        } catch (Throwable) {
            $offset = 0;
        }
        // @codeCoverageIgnoreEnd

        $name = @timezone_name_from_abbr('', $offset, $isDST);

        if ($name) {
            return $name;
        }

        foreach (timezone_identifiers_list() as $timezone) {
            if (Carbon::instance($date)->setTimezone($timezone)->getOffset() === $offset) {
                return $timezone;
            }
        }

        return null;
    }

