private static function splitNoProxyHostAndPort(string $area): array
    {
        if ($area !== '' && $area[0] === '[') {
            $closingBracket = \strpos($area, ']');

            if ($closingBracket !== false) {
                $tail = \substr($area, $closingBracket + 1);
                if ($tail !== '' && $tail[0] === ':') {
                    $port = self::parseNoProxyPort(\substr($tail, 1));

                    if ($port !== null) {
                        return [\substr($area, 0, $closingBracket + 1), $port];
                    }
                }
            }

            return [$area, null];
        }

        if (\filter_var($area, \FILTER_VALIDATE_IP, \FILTER_FLAG_IPV6)) {
            return [$area, null];
        }

        $colon = \strrpos($area, ':');
        if ($colon === false) {
            return [$area, null];
        }

        $port = self::parseNoProxyPort(\substr($area, $colon + 1));
        if ($port === null) {
            return [$area, null];
        }

        return [\substr($area, 0, $colon), $port];
    }

public function intersectWith(SpecifiedTypes $other): self
	{
		$sureTypeUnion = [];
		$sureNotTypeUnion = [];
		$rootExpr = $this->mergeRootExpr($this->rootExpr, $other->rootExpr);

		foreach ($this->sureTypes as $exprString => [$exprNode, $type]) {
			if (!isset($other->sureTypes[$exprString])) {
				continue;
			}

			$sureTypeUnion[$exprString] = [
				$exprNode,
				TypeCombinator::union($type, $other->sureTypes[$exprString][1]),
			];
		}

		foreach ($this->sureNotTypes as $exprString => [$exprNode, $type]) {
			if (!isset($other->sureNotTypes[$exprString])) {
				continue;
			}

			$sureNotTypeUnion[$exprString] = [
				$exprNode,
				TypeCombinator::intersect($type, $other->sureNotTypes[$exprString][1]),
			];
		}

		$result = new self($sureTypeUnion, $sureNotTypeUnion);
		if ($this->overwrite && $other->overwrite) {
			$result = $result->setAlwaysOverwriteTypes();
		}

		return $result->setRootExpr($rootExpr);
	}

public function resolveIdentical(Expr\BinaryOp\Identical $expr, Scope $scope, TypeSpecifierContext $context): SpecifiedTypes
	{
		$leftExpr = $expr->left;
		$rightExpr = $expr->right;

		// Normalize to: fn() === expr
		if ($rightExpr instanceof FuncCall && !$leftExpr instanceof FuncCall) {
			$specifiedTypes = $this->resolveNormalizedIdentical(new Expr\BinaryOp\Identical(
				$rightExpr,
				$leftExpr,
			), $scope, $context);
		} else {
			$specifiedTypes = $this->resolveNormalizedIdentical(new Expr\BinaryOp\Identical(
				$leftExpr,
				$rightExpr,
			), $scope, $context);
		}

		// merge result of fn1() === fn2() and fn2() === fn1()
		if ($rightExpr instanceof FuncCall && $leftExpr instanceof FuncCall) {
			return $specifiedTypes->unionWith(
				$this->resolveNormalizedIdentical(new Expr\BinaryOp\Identical(
					$rightExpr,
					$leftExpr,
				), $scope, $context),
			);
		}

		return $specifiedTypes;
	}

public function parseFile(string $file): array
	{
		$normalizedPath = $this->fileHelper->normalizePath($file, '/');
		if (str_contains($normalizedPath, 'vendor/jetbrains/phpstorm-stubs')) {
			return $this->php8Parser->parseFile($file);
		}
		if (str_contains($normalizedPath, 'vendor/phpstan/php-8-stubs/stubs')) {
			return $this->php8Parser->parseFile($file);
		}

		$file = $this->fileHelper->normalizePath($file);
		if (!isset($this->analysedFiles[$file]) && $file !== $this->singleReflectionFile) {
			// check symlinked file that still might be in analysedFiles
			$pathParts = explode(DIRECTORY_SEPARATOR, $file);
			for ($i = count($pathParts); $i > 1; $i--) {
				$joinedPartOfPath = implode(DIRECTORY_SEPARATOR, array_slice($pathParts, 0, $i));
				if (!@is_link($joinedPartOfPath)) {
					continue;
				}

				$realFilePath = realpath($file);
				if ($realFilePath !== false) {
					$normalizedRealFilePath = $this->fileHelper->normalizePath($realFilePath);
					if (isset($this->analysedFiles[$normalizedRealFilePath])) {
						return $this->currentPhpVersionRichParser->parseFile($file);
					}
				}
				break;
			}

			return $this->currentPhpVersionSimpleParser->parseFile($file);
		}

		return $this->currentPhpVersionRichParser->parseFile($file);
	}

private function resolveConstantReflections(Expr $expr, Scope $scope): ?array
	{
		if ($expr instanceof Expr\ConstFetch) {
			$lowerName = $expr->name->toLowerString();
			if (in_array($lowerName, ['null', 'true', 'false'], true)) {
				return null;
			}

			if (!$this->reflectionProvider->hasConstant($expr->name, $scope)) {
				return null;
			}

			return [$this->reflectionProvider->getConstant($expr->name, $scope)];
		}

		if ($expr instanceof Expr\ClassConstFetch) {
			if (!$expr->class instanceof Node\Name) {
				return null;
			}
			if (!$expr->name instanceof Node\Identifier) {
				return null;
			}

			$className = $scope->resolveName($expr->class);
			if (!$this->reflectionProvider->hasClass($className)) {
				return null;
			}

			$classReflection = $this->reflectionProvider->getClass($className);
			if (!$classReflection->hasConstant($expr->name->name)) {
				return null;
			}

			return [$classReflection->getConstant($expr->name->name)];
		}

		if ($expr instanceof Expr\BinaryOp\BitwiseOr) {
			$left = $this->resolveConstantReflections($expr->left, $scope);
			$right = $this->resolveConstantReflections($expr->right, $scope);
			if ($left === null || $right === null) {
				return null;
			}

			return [...$left, ...$right];
		}

		return null;
	}

private function getErrorMessage(Include_ $node, string $filePath): IdentifierRuleError
	{
		$message = 'Path in %s() "%s" is not a file or it does not exist.';

		switch ($node->type) {
			case Include_::TYPE_REQUIRE:
				$type = 'require';
				$identifierType = 'require';
				break;
			case Include_::TYPE_REQUIRE_ONCE:
				$type = 'require_once';
				$identifierType = 'requireOnce';
				break;
			case Include_::TYPE_INCLUDE:
				$type = 'include';
				$identifierType = 'include';
				break;
			case Include_::TYPE_INCLUDE_ONCE:
				$type = 'include_once';
				$identifierType = 'includeOnce';
				break;
			default:
				throw new ShouldNotHappenException('Rule should have already validated the node type.');
		}

		$identifier = sprintf('%s.fileNotFound', $identifierType);

		return RuleErrorBuilder::message(
			sprintf(
				$message,
				$type,
				$filePath,
			),
		)->identifier($identifier)->build();
	}

private function checkParameterTypeCompatibility(
	ClassReflection $declaringClass,
	array $parameters,
	array $parentParameters,
): array
{
	$parameterResults = [];

	$numberOfParameters = min(count($parameters), count($parentParameters));
	for ($i = 0; $i < $numberOfParameters; $i++) {
		$parameter = $parameters[$i];
		$parentParameter = $parentParameters[$i];

		$parameterType = TypehintHelper::decideType(
			$parameter->getNativeType(),
			TemplateTypeHelper::resolveToBounds($parameter->getPhpDocType()),
		);
		$originalParameterType = TypehintHelper::decideType(
			$parentParameter->getNativeType(),
			TemplateTypeHelper::resolveToBounds($parentParameter->getPhpDocType()),
		);
		$parentParameterType = $this->transformStaticType($declaringClass, $originalParameterType);

		$parameterResults[] = [$parameterType->isSuperTypeOf($parentParameterType)->result, TypehintHelper::decideType(
			$parameter->getNativeType(),
			$parameter->getPhpDocType(),
		), $originalParameterType];
	}

	return $parameterResults;
}

protected function dumpFlags(int $flags): string {
    $strs = [];
    if ($flags & Modifiers::PUBLIC) {
        $strs[] = 'PUBLIC';
    }
    if ($flags & Modifiers::PROTECTED) {
        $strs[] = 'PROTECTED';
    }
    if ($flags & Modifiers::PRIVATE) {
        $strs[] = 'PRIVATE';
    }
    if ($flags & Modifiers::ABSTRACT) {
        $strs[] = 'ABSTRACT';
    }
    if ($flags & Modifiers::STATIC) {
        $strs[] = 'STATIC';
    }
    if ($flags & Modifiers::FINAL) {
        $strs[] = 'FINAL';
    }
    if ($flags & Modifiers::READONLY) {
        $strs[] = 'READONLY';
    }
    if ($flags & Modifiers::PUBLIC_SET) {
        $strs[] = 'PUBLIC_SET';
    }
    if ($flags & Modifiers::PROTECTED_SET) {
        $strs[] = 'PROTECTED_SET';
    }
    if ($flags & Modifiers::PRIVATE_SET) {
        $strs[] = 'PRIVATE_SET';
    }

    if ($strs) {
        return implode(' | ', $strs) . ' (' . $flags . ')';
    } else {
        return (string) $flags;
    }
}

